import React from 'react';

const Taskbar = ({ handleMouseEnter, handleMouseLeave, handleClick }) => {
  const taskbarApps = [
    { name: 'View Github and other projects', id: 1 },
    { name: 'About Me', id: 2 },
    { name: 'Contact Me', id: 3 },
  ];

  return (
    <div className="taskbar">
      {taskbarApps.map((app) => (
        <div
          key={app.id}
          className="taskbar-app"
          onMouseEnter={handleMouseEnter}
          onMouseLeave={handleMouseLeave}
          onClick={handleClick}
        >
          {app.name}
        </div>
      ))}
    </div>
  );
};

export default Taskbar;
